var UserConnection = Get<UserConnection>("UserConnection");
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
	var service = new ConfirmPortInService(UserConnection);

    service.SetParam(lineDetailId);
    Set("Request", service.GetStringRequest());
    service.Request().GetAwaiter().GetResult();
    
    Set("Response", service.GetStringResponse()); 
    Set("Success", service.IsSuccessResponse()); 
} catch (Exception e) {
    Set("Response", e.Message);
}

return true;
